import{_ as a,o as l,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const f=JSON.parse('{"title":"GEICO（政府雇员保险公司）","description":"","frontmatter":{},"headers":[],"relativePath":"03_companies/GEICO.md","filePath":"03_companies/GEICO.md"}'),h={name:"03_companies/GEICO.md"};function i(d,t,o,s,n,m){return l(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="geico-政府雇员保险公司" tabindex="-1">GEICO（政府雇员保险公司） <a class="header-anchor" href="#geico-政府雇员保险公司" aria-label="Permalink to &quot;GEICO（政府雇员保险公司）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>英文名</td><td>GEICO (Government Employees Insurance Company)</td></tr><tr><td>行业</td><td>汽车保险</td></tr><tr><td>成立年份</td><td>1936年</td></tr><tr><td>总部</td><td>马里兰州 Chevy Chase</td></tr><tr><td>伯克希尔持股</td><td>约35%-41%（非控股）</td></tr><tr><td>投资成本</td><td>约4,700万美元（1976年前后开始买入）</td></tr></tbody></table><h2 id="核心业务" tabindex="-1">核心业务 <a class="header-anchor" href="#核心业务" aria-label="Permalink to &quot;核心业务&quot;">​</a></h2><p>GEICO是美国最大的汽车保险直销公司之一，通过电话和网络直接面向消费者销售保险产品，省去中间代理商环节，实现低成本运营。</p><h2 id="伯克希尔投资历程" tabindex="-1">伯克希尔投资历程 <a class="header-anchor" href="#伯克希尔投资历程" aria-label="Permalink to &quot;伯克希尔投资历程&quot;">​</a></h2><h3 id="买入背景" tabindex="-1">买入背景 <a class="header-anchor" href="#买入背景" aria-label="Permalink to &quot;买入背景&quot;">​</a></h3><ul><li><strong>1976年</strong>：GEICO因激进扩张和定价失误濒临破产，股价从高点暴跌</li><li>巴菲特认定其核心竞争优势（低成本模式）依然完好，开始大举买入</li><li>时任CEO杰克·伯恩（Jack Byrne）成功扭转局面</li></ul><h3 id="持仓变化" tabindex="-1">持仓变化 <a class="header-anchor" href="#持仓变化" aria-label="Permalink to &quot;持仓变化&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>持股数</th><th>备注</th></tr></thead><tbody><tr><td>1978</td><td>720万股</td><td>主要持仓</td></tr><tr><td>1981</td><td>720万股</td><td>持仓稳定</td></tr><tr><td>1987</td><td>690万股</td><td>持仓稳定</td></tr></tbody></table><h3 id="投资回报" tabindex="-1">投资回报 <a class="header-anchor" href="#投资回报" aria-label="Permalink to &quot;投资回报&quot;">​</a></h3><ul><li><strong>未分配盈利</strong>：1981年约2,000万美元/年</li><li><strong>分红收入</strong>：稳定现金分红</li><li><strong>市值增长</strong>：持仓市值从约4,700万美元成本增长至数亿美元</li></ul><h2 id="核心竞争优势" tabindex="-1">核心竞争优势 <a class="header-anchor" href="#核心竞争优势" aria-label="Permalink to &quot;核心竞争优势&quot;">​</a></h2><h3 id="_1-低成本运营模式" tabindex="-1">1. 低成本运营模式 <a class="header-anchor" href="#_1-低成本运营模式" aria-label="Permalink to &quot;1. 低成本运营模式&quot;">​</a></h3><ul><li>无代理商佣金，直销模式节省15-20%成本</li><li>目标客户：政府雇员、军人等低风险群体</li><li>精细化承保选择</li></ul><h3 id="_2-效率优势" tabindex="-1">2. 效率优势 <a class="header-anchor" href="#_2-效率优势" aria-label="Permalink to &quot;2. 效率优势&quot;">​</a></h3><ul><li><strong>综合成本率</strong>：1983年仅96，远优于行业111</li><li>保费增长快于行业，同时保持承保盈利</li><li>投资组合管理出色（Lou Simpson负责）</li></ul><h3 id="_3-品牌优势" tabindex="-1">3. 品牌优势 <a class="header-anchor" href="#_3-品牌优势" aria-label="Permalink to &quot;3. 品牌优势&quot;">​</a></h3><ul><li>&quot;15分钟省15%&quot;广告深入人心</li><li>高续保率客户群</li></ul><h2 id="管理团队" tabindex="-1">管理团队 <a class="header-anchor" href="#管理团队" aria-label="Permalink to &quot;管理团队&quot;">​</a></h2><h3 id="关键人物" tabindex="-1">关键人物 <a class="header-anchor" href="#关键人物" aria-label="Permalink to &quot;关键人物&quot;">​</a></h3><table tabindex="0"><thead><tr><th>姓名</th><th>职位</th><th>贡献</th></tr></thead><tbody><tr><td><a href="./../04_人物库/杰克·伯恩.html">杰克·伯恩</a></td><td>CEO（1976-1985）</td><td>从破产边缘拯救公司，重建承保纪律</td></tr><tr><td><a href="./../04_人物库/比尔·斯奈德.html">比尔·斯奈德</a></td><td>董事长（1985年后）</td><td>继续压低成本，巩固特许权</td></tr><tr><td><a href="./../04_人物库/卢·辛普森.html">卢·辛普森</a></td><td>投资副总裁</td><td>管理GEICO投资组合，长期跑赢标普500</td></tr><tr><td>沃伦·巴菲特</td><td>董事会成员</td><td>1976年进入董事会，提供战略指导</td></tr></tbody></table><h3 id="管理特点" tabindex="-1">管理特点 <a class="header-anchor" href="#管理特点" aria-label="Permalink to &quot;管理特点&quot;">​</a></h3><ul><li>承保纪律严格，不惜削减业务保持盈利</li><li>成本控制极致，持续压低运营费用率</li><li>投资保守稳健，避免高风险资产</li></ul><h2 id="巴菲特评价摘录" tabindex="-1">巴菲特评价摘录 <a class="header-anchor" href="#巴菲特评价摘录" aria-label="Permalink to &quot;巴菲特评价摘录&quot;">​</a></h2><blockquote><p>&quot;GEICO拥有极端且不断提升的运营效率，其成本优势广泛且可持续。&quot; —— 1983年股东信</p></blockquote><blockquote><p>&quot;GEICO是我们最重要的非控股持仓，代表伯克希尔最大的未分配盈利来源。&quot; —— 1981年股东信</p></blockquote><blockquote><p>&quot;卢·辛普森是财产意外险行业最好的投资经理。&quot; —— 1984年股东信</p></blockquote><h2 id="财务表现-摘录" tabindex="-1">财务表现（摘录） <a class="header-anchor" href="#财务表现-摘录" aria-label="Permalink to &quot;财务表现（摘录）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>保费收入</th><th>综合成本率</th><th>备注</th></tr></thead><tbody><tr><td>1981</td><td>约2.7亿美元</td><td>约98</td><td>远优于行业</td></tr><tr><td>1983</td><td>约3.5亿美元</td><td>96</td><td>行业最佳</td></tr><tr><td>1986</td><td>超5亿美元</td><td>96.9</td><td>三年翻倍</td></tr></tbody></table><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1977, 1978, 1979, 1980, 1981, 1982, 1983, 1984, 1985, 1986, 1987</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./喜诗糖果.html">喜诗糖果</a> - 同为核心控股子公司</li><li><a href="./华盛顿邮报.html">华盛顿邮报</a> - 同为主要非控股持仓</li><li><a href="./国家赔偿公司.html">国家赔偿公司</a> - 伯克希尔保险板块核心</li></ul><hr><p><em>最后更新：2026-04-09</em></p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/1980年/翻译.html">1980年</a></li><li><a href="./../01_letters/1981年/翻译.html">1981年</a></li><li><a href="./../01_letters/1982年/翻译.html">1982年</a></li><li><a href="./../01_letters/1983年/翻译.html">1983年</a></li><li><a href="./../01_letters/1984年/翻译.html">1984年</a></li><li><a href="./../01_letters/1985年/翻译.html">1985年</a></li><li><a href="./../01_letters/1986年/翻译.html">1986年</a></li><li><a href="./../01_letters/1987年/翻译.html">1987年</a></li><li><a href="./../01_letters/1988年/翻译.html">1988年</a></li><li><a href="./../01_letters/1989年/翻译.html">1989年</a></li><li><a href="./../01_letters/1990年/翻译.html">1990年</a></li><li><a href="./../01_letters/1991年/翻译.html">1991年</a></li><li><a href="./../01_letters/1994年/翻译.html">1994年</a></li><li><a href="./../01_letters/1995年/翻译.html">1995年</a></li><li><a href="./../01_letters/1997年/翻译.html">1997年</a></li><li><a href="./../01_letters/1998年/翻译.html">1998年</a></li><li><a href="./../01_letters/1999年/翻译.html">1999年</a></li><li><a href="./../01_letters/2000年/翻译.html">2000年</a></li><li><a href="./../01_letters/2001年/翻译.html">2001年</a></li><li><a href="./../01_letters/2002年/翻译.html">2002年</a></li><li><a href="./../01_letters/2003年/翻译.html">2003年</a></li><li><a href="./../01_letters/2004年/翻译.html">2004年</a></li><li><a href="./../01_letters/2005年/翻译.html">2005年</a></li><li><a href="./../01_letters/2006年/翻译.html">2006年</a></li><li><a href="./../01_letters/2007年/翻译.html">2007年</a></li><li><a href="./../01_letters/2008年/翻译.html">2008年</a></li><li><a href="./../01_letters/2009年/翻译.html">2009年</a></li><li><a href="./../01_letters/2010年/翻译.html">2010年</a></li><li><a href="./../01_letters/2011年/翻译.html">2011年</a></li><li><a href="./../01_letters/2012年/翻译.html">2012年</a></li><li><a href="./../01_letters/2013年/翻译.html">2013年</a></li><li><a href="./../01_letters/2014年/翻译.html">2014年</a></li><li><a href="./../01_letters/2015年/翻译.html">2015年</a></li><li><a href="./../01_letters/2016年/翻译.html">2016年</a></li></ul>',38)])])}const _=a(h,[["render",i]]);export{f as __pageData,_ as default};
